+// =========================================
+// /dev/agnocast
+
+#define AGNOCAST_TOPIC_ADD_CMD _IOW('T', 1, char *)
+void topic_add(const char *topic_name) {
+	struct topic_wrapper *wrapper = find_topic(topic_name);
+	if (wrapper) {
